"use strict";(self.webpackChunkmy_blog=self.webpackChunkmy_blog||[]).push([[72835],{66262:(n,e)=>{e.A=(n,e)=>{const s=n.__vccOpts||n;for(const[n,a]of e)s[n]=a;return s}},8146:(n,e,s)=>{s.r(e),s.d(e,{comp:()=>h,data:()=>v});var a=s(20641);const i=s.p+"assets/img/Ciqc1F90P1yAYThvAADLV6SJeac973.508c3c9c.png",l=s.p+"assets/img/CgqCHl9wcRiAZFTaAADTxIPND7k175.00d15c1e.png",p=s.p+"assets/img/Ciqc1F9wcSGAXo7JAANZ2BjquOE739.37702811.png",r=s.p+"assets/img/CgqCHl9wcTGAdInYAAJOSSxusf4539.cf887b04.png",t=s.p+"assets/img/CgqCHl9wcUWAY3b0AAFKI4e5Oa0017.d61f9b35.png",d=s.p+"assets/img/CgqCHl9wcVCAQdJjAAFE8eFivcY750.27b369f8.png",c=s.p+"assets/img/Ciqc1F9wcV-AFAcTAADpElrp-Wc888.0e33cd26.png",u=s.p+"assets/img/CgqCHl9wcWaAJVA3AACBSF4eCzg786.1ea44e96.png",o={},h=(0,s(66262).A)(o,[["render",function(n,e){return(0,a.uX)(),(0,a.CE)("div",null,e[0]||(e[0]=[(0,a.Fv)('<h1 id="_20-transporter-层核心实现-编解码与线程模型一文打尽-下" tabindex="-1"><a class="header-anchor" href="#_20-transporter-层核心实现-编解码与线程模型一文打尽-下"><span>20 Transporter 层核心实现：编解码与线程模型一文打尽（下）</span></a></h1><p>在上一课时中，我们深入分析了 Transporter 层中 Server 相关的核心抽象类以及基于 Netty 4 的实现类。本课时我们继续分析 Transporter 层中剩余的核心接口实现，主要涉及 Client 接口、Channel 接口、ChannelHandler 接口，以及相关的关键组件。</p><h3 id="client-继承路线分析" tabindex="-1"><a class="header-anchor" href="#client-继承路线分析"><span>Client 继承路线分析</span></a></h3><p>在上一课时分析 AbstractEndpoint 的时候可以看到，除了 AbstractServer 这一条继承线之外，还有 AbstractClient 这条继承线，它是对客户端的抽象。AbstractClient 中的核心字段有如下几个。</p><ul><li>connectLock（Lock 类型）：在 Client 底层进行连接、断开、重连等操作时，需要获取该锁进行同步。</li><li>needReconnect（Boolean 类型）：在发送数据之前，会检查 Client 底层的连接是否断开，如果断开了，则会根据 needReconnect 字段，决定是否重连。</li><li>executor（ExecutorService 类型）：当前 Client 关联的线程池，线程池的具体内容在上一课时已经详细介绍过了，这里不再赘述。</li></ul><p>在 AbstractClient 的构造方法中，会解析 URL 初始化 needReconnect 字段和 executor字段，如下示例代码：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public AbstractClient(URL url, ChannelHandler handler) throws RemotingException {</span></span>\n<span class="line"><span>    super(url, handler); // 调用父类的构造方法</span></span>\n<span class="line"><span>    // 解析URL，初始化needReconnect值</span></span>\n<span class="line"><span>    needReconnect = url.getParameter(&quot;send.reconnect&quot;, false);</span></span>\n<span class="line"><span>    initExecutor(url);     // 解析URL，初始化executor</span></span>\n<span class="line"><span>    doOpen();    // 初始化底层的NIO库的相关组件</span></span>\n<span class="line"><span>    // 创建底层连接</span></span>\n<span class="line"><span>    connect(); // 省略异常处理的逻辑</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>与 AbstractServer 类似，AbstractClient 定义了 doOpen()、doClose()、doConnect()和doDisConnect() 四个抽象方法给子类实现。</p><p>下面来看基于 Netty 4 实现的 NettyClient，它继承了 AbstractClient 抽象类，实现了上述四个 do*() 抽象方法，我们这里重点关注 doOpen() 方法和 doConnect() 方法。在 NettyClient 的 doOpen() 方法中会通过 Bootstrap 构建客户端，其中会完成连接超时时间、keepalive 等参数的设置，以及 ChannelHandler 的创建和注册，具体实现如下所示：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>protected void doOpen() throws Throwable {</span></span>\n<span class="line"><span>    // 创建NettyClientHandler</span></span>\n<span class="line"><span>    final NettyClientHandler nettyClientHandler = new NettyClientHandler(getUrl(), this);</span></span>\n<span class="line"><span>    bootstrap = new Bootstrap(); // 创建Bootstrap</span></span>\n<span class="line"><span>    bootstrap.group(NIO_EVENT_LOOP_GROUP)</span></span>\n<span class="line"><span>            .option(ChannelOption.SO_KEEPALIVE, true)</span></span>\n<span class="line"><span>            .option(ChannelOption.TCP_NODELAY, true)</span></span>\n<span class="line"><span>            .option(ChannelOption.ALLOCATOR, PooledByteBufAllocator.DEFAULT)</span></span>\n<span class="line"><span>            .channel(socketChannelClass());</span></span>\n<span class="line"><span>    // 设置连接超时时间，这里使用到AbstractEndpoint中的connectTimeout字段</span></span>\n<span class="line"><span>    bootstrap.option(ChannelOption.CONNECT_TIMEOUT_MILLIS, Math.max(3000, getConnectTimeout()));</span></span>\n<span class="line"><span>    bootstrap.handler(new ChannelInitializer&lt;SocketChannel&gt;() {</span></span>\n<span class="line"><span>        protected void initChannel(SocketChannel ch) throws Exception {</span></span>\n<span class="line"><span>            // 心跳请求的时间间隔</span></span>\n<span class="line"><span>            int heartbeatInterval = UrlUtils.getHeartbeat(getUrl());</span></span>\n<span class="line"><span>            // 通过NettyCodecAdapter创建Netty中的编解码器，这里不再重复介绍</span></span>\n<span class="line"><span>            NettyCodecAdapter adapter = new NettyCodecAdapter(getCodec(), getUrl(), NettyClient.this);</span></span>\n<span class="line"><span>            // 注册ChannelHandler</span></span>\n<span class="line"><span>            ch.pipeline().addLast(&quot;decoder&quot;, adapter.getDecoder())</span></span>\n<span class="line"><span>                    .addLast(&quot;encoder&quot;, adapter.getEncoder())</span></span>\n<span class="line"><span>                    .addLast(&quot;client-idle-handler&quot;, new IdleStateHandler(heartbeatInterval, 0, 0, MILLISECONDS))</span></span>\n<span class="line"><span>                    .addLast(&quot;handler&quot;, nettyClientHandler);</span></span>\n<span class="line"><span>            // 如果需要Socks5Proxy，需要添加Socks5ProxyHandler(略)</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    });</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>得到的 NettyClient 结构如下图所示：</p><figure><img src="'+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>NettyClient 结构图</p><p>NettyClientHandler 的实现方法与上一课时介绍的 NettyServerHandler 类似，同样是实现了 Netty 中的 ChannelDuplexHandler，其中会将所有方法委托给 NettyClient 关联的 ChannelHandler 对象进行处理。两者在 userEventTriggered() 方法的实现上有所不同，NettyServerHandler 在收到 IdleStateEvent 事件时会断开连接，而 NettyClientHandler 则会发送心跳消息，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void userEventTriggered(ChannelHandlerContext ctx, Object evt) throws Exception {</span></span>\n<span class="line"><span>    if (evt instanceof IdleStateEvent) {</span></span>\n<span class="line"><span>        NettyChannel channel = NettyChannel.getOrAddChannel(ctx.channel(), url, handler);</span></span>\n<span class="line"><span>        Request req = new Request(); </span></span>\n<span class="line"><span>        req.setVersion(Version.getProtocolVersion());</span></span>\n<span class="line"><span>        req.setTwoWay(true);</span></span>\n<span class="line"><span>        req.setEvent(HEARTBEAT_EVENT); // 发送心跳请求</span></span>\n<span class="line"><span>        channel.send(req);</span></span>\n<span class="line"><span>    } else {</span></span>\n<span class="line"><span>        super.userEventTriggered(ctx, evt);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="channel-继承线分析" tabindex="-1"><a class="header-anchor" href="#channel-继承线分析"><span>Channel 继承线分析</span></a></h3><p>除了上一课时介绍的 AbstractEndpoint 之外，AbstractChannel 也继承了 AbstractPeer 这个抽象类，同时还继承了 Channel 接口。AbstractChannel 实现非常简单，只是在 send() 方法中检测了底层连接的状态，没有实现具体的发送消息的逻辑。</p><p>这里我们依然以基于 Netty 4 的实现—— NettyChannel 为例，分析它对 AbstractChannel 的实现。NettyChannel 中的核心字段有如下几个。</p><ul><li>channel（Channel类型）：Netty 框架中的 Channel，与当前的 Dubbo Channel 对象一一对应。</li><li>attributes（<code>Map&lt;String, Object&gt;</code>类型）：当前 Channel 中附加属性，都会记录到该 Map 中。NettyChannel 中提供的 getAttribute()、hasAttribute()、setAttribute() 等方法，都是操作该集合。</li><li>active（AtomicBoolean）：用于标识当前 Channel 是否可用。</li></ul><p>另外，在 NettyChannel 中还有一个静态的 Map 集合（CHANNEL_MAP 字段），用来缓存当前 JVM 中 Netty 框架 Channel 与 Dubbo Channel 之间的映射关系。从下图的调用关系中可以看到，NettyChannel 提供了读写 CHANNEL_MAP 集合的方法：</p><figure><img src="'+l+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>NettyChannel 中还有一个要介绍的是 send() 方法，它会通过底层关联的 Netty 框架 Channel，将数据发送到对端。其中，可以通过第二个参数指定是否等待发送操作结束，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void send(Object message, boolean sent) throws RemotingException {</span></span>\n<span class="line"><span>    // 调用AbstractChannel的send()方法检测连接是否可用</span></span>\n<span class="line"><span>    super.send(message, sent); </span></span>\n<span class="line"><span>    boolean success = true;</span></span>\n<span class="line"><span>    int timeout = 0;</span></span>\n<span class="line"><span>    // 依赖Netty框架的Channel发送数据</span></span>\n<span class="line"><span>    ChannelFuture future = channel.writeAndFlush(message);</span></span>\n<span class="line"><span>    if (sent) { // 等待发送结束，有超时时间</span></span>\n<span class="line"><span>        timeout = getUrl().getPositiveParameter(TIMEOUT_KEY, DEFAULT_TIMEOUT);</span></span>\n<span class="line"><span>        success = future.await(timeout);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    Throwable cause = future.cause();</span></span>\n<span class="line"><span>    if (cause != null) {</span></span>\n<span class="line"><span>        throw cause;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 出现异常会调用removeChannelIfDisconnected()方法，在底层连接断开时，</span></span>\n<span class="line"><span>    // 会清理CHANNEL_MAP缓存(略)</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="channelhandler-继承线分析" tabindex="-1"><a class="header-anchor" href="#channelhandler-继承线分析"><span>ChannelHandler 继承线分析</span></a></h3><p>前文介绍的 AbstractServer、AbstractClient 以及 Channel 实现，都是通过 AbstractPeer 实现了 ChannelHandler 接口，但只是做了一层简单的委托（也可以说成是装饰器），将全部方法委托给了其底层关联的 ChannelHandler 对象。</p><p>这里我们就深入分析 ChannelHandler 的其他实现类，涉及的实现类如下所示：</p><figure><img src="'+p+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>ChannelHandler 继承关系图</p><p>其中<strong>ChannelHandlerDispatcher</strong>在[第 17 课时]已经介绍过了，它负责将多个 ChannelHandler 对象聚合成一个 ChannelHandler 对象。</p><p><strong>ChannelHandlerAdapter</strong>是 ChannelHandler 的一个空实现，TelnetHandlerAdapter 继承了它并实现了 TelnetHandler 接口。至于Dubbo 对 Telnet 的支持，我们会在后面的课时中单独介绍，这里就先不展开分析了。</p><p>从名字上看，<strong>ChannelHandlerDelegate</strong>接口是对另一个 ChannelHandler 对象的封装，它的两个实现类 AbstractChannelHandlerDelegate 和 WrappedChannelHandler 中也仅仅是封装了另一个 ChannelHandler 对象。</p><p>其中，<strong>AbstractChannelHandlerDelegate</strong>有三个实现类，都比较简单，我们来逐个讲解。</p><ul><li>MultiMessageHandler：专门处理 MultiMessage 的 ChannelHandler 实现。MultiMessage 是 Exchange 层的一种消息类型，它其中封装了多个消息。在 MultiMessageHandler 收到 MultiMessage 消息的时候，received() 方法会遍历其中的所有消息，并交给底层的 ChannelHandler 对象进行处理。</li><li>DecodeHandler：专门处理 Decodeable 的 ChannelHandler 实现。实现了 Decodeable 接口的类都会提供了一个 decode() 方法实现对自身的解码，DecodeHandler.received() 方法就是通过该方法得到解码后的消息，然后传递给底层的 ChannelHandler 对象继续处理。</li><li>HeartbeatHandler：专门处理心跳消息的 ChannelHandler 实现。在 HeartbeatHandler.received() 方法接收心跳请求的时候，会生成相应的心跳响应并返回；在收到心跳响应的时候，会打印相应的日志；在收到其他类型的消息时，会传递给底层的 ChannelHandler 对象进行处理。下面是其核心实现：</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void received(Channel channel, Object message) throws RemotingException {</span></span>\n<span class="line"><span>    setReadTimestamp(channel); // 记录最近的读写事件时间戳</span></span>\n<span class="line"><span>    if (isHeartbeatRequest(message)) { // 收到心跳请求</span></span>\n<span class="line"><span>        Request req = (Request) message;</span></span>\n<span class="line"><span>        if (req.isTwoWay()) { // 返回心跳响应，注意，携带请求的ID</span></span>\n<span class="line"><span>            Response res = new Response(req.getId(), req.getVersion());</span></span>\n<span class="line"><span>            res.setEvent(HEARTBEAT_EVENT);</span></span>\n<span class="line"><span>            channel.send(res);</span></span>\n<span class="line"><span>        return;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    if (isHeartbeatResponse(message)) { // 收到心跳响应</span></span>\n<span class="line"><span>        // 打印日志(略)</span></span>\n<span class="line"><span>        return;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    handler.received(channel, message);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>另外，我们可以看到，在 received() 和 send() 方法中，HeartbeatHandler 会将最近一次的读写时间作为附加属性记录到 Channel 中。</p><p>通过上述介绍，我们发现 AbstractChannelHandlerDelegate 下的三个实现，其实都是在原有 ChannelHandler 的基础上添加了一些增强功能，这是典型的装饰器模式的应用。</p><h4 id="dispatcher-与-channelhandler" tabindex="-1"><a class="header-anchor" href="#dispatcher-与-channelhandler"><span>Dispatcher 与 ChannelHandler</span></a></h4><p>接下来，我们介绍 ChannelHandlerDelegate 接口的另一条继承线——<strong>WrappedChannelHandler</strong>，其子类主要是决定了 Dubbo 以何种线程模型处理收到的事件和消息，就是所谓的“消息派发机制”，与前面介绍的 ThreadPool 有紧密的联系。</p><figure><img src="'+r+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>WrappedChannelHandler 继承关系图</p><p>从上图中我们可以看到，每个 WrappedChannelHandler 实现类的对象都由一个相应的 Dispatcher 实现类创建，下面是 Dispatcher 接口的定义：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>@SPI(AllDispatcher.NAME) // 默认扩展名是all</span></span>\n<span class="line"><span>public interface Dispatcher {</span></span>\n<span class="line"><span>    // 通过URL中的参数可以指定扩展名，覆盖默认扩展名</span></span>\n<span class="line"><span>    @Adaptive({&quot;dispatcher&quot;, &quot;dispather&quot;, &quot;channel.handler&quot;})</span></span>\n<span class="line"><span>    ChannelHandler dispatch(ChannelHandler handler, URL url);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>AllDispatcher 创建的是 AllChannelHandler 对象</strong>，它会将所有网络事件以及消息交给关联的线程池进行处理。AllChannelHandler覆盖了 WrappedChannelHandler 中除了 sent() 方法之外的其他网络事件处理方法，将调用其底层的 ChannelHandler 的逻辑放到关联的线程池中执行。</p><p>我们先来看 connect() 方法，其中会将CONNECTED 事件的处理封装成ChannelEventRunnable提交到线程池中执行，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void connected(Channel channel) throws RemotingException {</span></span>\n<span class="line"><span>    ExecutorService executor = getExecutorService(); // 获取公共线程池</span></span>\n<span class="line"><span>    // 将CONNECTED事件的处理封装成ChannelEventRunnable提交到线程池中执行</span></span>\n<span class="line"><span>    executor.execute(new ChannelEventRunnable(channel, handler, ChannelState.CONNECTED));</span></span>\n<span class="line"><span>    // 省略异常处理的逻辑</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里的 getExecutorService() 方法会按照当前端点（Server/Client）的 URL 从 ExecutorRepository 中获取相应的公共线程池。</p><p>disconnected()方法处理连接断开事件，caught() 方法处理异常事件，它们也是按照上述方式实现的，这里不再展开赘述。</p><p>received() 方法会在当前端点收到数据的时候被调用，具体执行流程是先由 IO 线程（也就是 Netty 中的 EventLoopGroup）从二进制流中解码出请求，然后调用 AllChannelHandler 的 received() 方法，其中会将请求提交给线程池执行，执行完后调用 sent()方法，向对端写回响应结果。received() 方法的具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void received(Channel channel, Object message) throws RemotingException {</span></span>\n<span class="line"><span>    // 获取线程池</span></span>\n<span class="line"><span>    ExecutorService executor = getPreferredExecutorService(message);</span></span>\n<span class="line"><span>    try {</span></span>\n<span class="line"><span>        // 将消息封装成ChannelEventRunnable任务，提交到线程池中执行</span></span>\n<span class="line"><span>        executor.execute(new ChannelEventRunnable(channel, handler, ChannelState.RECEIVED, message));</span></span>\n<span class="line"><span>    } catch (Throwable t) {</span></span>\n<span class="line"><span>        // 如果线程池满了，请求会被拒绝，这里会根据请求配置决定是否返回一个说明性的响应</span></span>\n<span class="line"><span>        if(message instanceof Request &amp;&amp; t instanceof RejectedExecutionException){</span></span>\n<span class="line"><span>            sendFeedback(channel, (Request) message, t);</span></span>\n<span class="line"><span>            return;</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        throw new ExecutionException(&quot;...&quot;);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>getPreferredExecutorService() 方法对响应做了特殊处理：如果请求在发送的时候指定了关联的线程池，在收到对应的响应消息的时候，会优先根据请求的 ID 查找请求关联的线程池处理响应。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public ExecutorService getPreferredExecutorService(Object msg) {</span></span>\n<span class="line"><span>    if (msg instanceof Response) {</span></span>\n<span class="line"><span>        Response response = (Response) msg;</span></span>\n<span class="line"><span>        DefaultFuture responseFuture = DefaultFuture.getFuture(response.getId()); // 获取请求关联的DefaultFuture</span></span>\n<span class="line"><span>        if (responseFuture == null) { </span></span>\n<span class="line"><span>            return getSharedExecutorService();</span></span>\n<span class="line"><span>        } else { // 如果请求关联了线程池，则会获取相关的线程来处理响应</span></span>\n<span class="line"><span>            ExecutorService executor = responseFuture.getExecutor();</span></span>\n<span class="line"><span>            if (executor == null || executor.isShutdown()) {</span></span>\n<span class="line"><span>                executor = getSharedExecutorService();</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>            return executor;</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    } else { // 如果是请求消息，则直接使用公共的线程池处理</span></span>\n<span class="line"><span>        return getSharedExecutorService();</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里涉及了 Request 和 Response 的概念，是 Exchange 层的概念，在后面会展开介绍，这里你只需要知道它们是不同的消息类型即可。</p><p>注意，AllChannelHandler 并没有覆盖父类的 sent() 方法，也就是说，发送消息是直接在当前线程调用 sent() 方法完成的。</p><p>下面我们来看剩余的 WrappedChannelHandler 的实现。ExecutionChannelHandler（由 ExecutionDispatcher 创建）只会将请求消息派发到线程池进行处理，也就是只重写了 received() 方法。对于响应消息以及其他网络事件（例如，连接建立事件、连接断开事件、心跳消息等），ExecutionChannelHandler 会直接在 IO 线程中进行处理。</p><p>DirectChannelHandler 实现（由 DirectDispatcher 创建）会在 IO 线程中处理所有的消息和网络事件。</p><p>MessageOnlyChannelHandler 实现（由 MessageOnlyDispatcher 创建）会将所有收到的消息提交到线程池处理，其他网络事件则是由 IO 线程直接处理。</p><p>ConnectionOrderedChannelHandler 实现（由 ConnectionOrderedDispatcher 创建）会将收到的消息交给线程池进行处理，对于连接建立以及断开事件，会提交到一个独立的线程池并排队进行处理。在 ConnectionOrderedChannelHandler 的构造方法中，会初始化一个线程池，该线程池的队列长度是固定的：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public ConnectionOrderedChannelHandler(ChannelHandler handler, URL url) {</span></span>\n<span class="line"><span>    super(handler, url);</span></span>\n<span class="line"><span>    String threadName = url.getParameter(THREAD_NAME_KEY, DEFAULT_THREAD_NAME);</span></span>\n<span class="line"><span>    // 注意，该线程池只有一个线程，队列的长度也是固定的，</span></span>\n<span class="line"><span>    // 由URL中的connect.queue.capacity参数指定</span></span>\n<span class="line"><span>    connectionExecutor = new ThreadPoolExecutor(1, 1, </span></span>\n<span class="line"><span>            0L, TimeUnit.MILLISECONDS,</span></span>\n<span class="line"><span>            new LinkedBlockingQueue&lt;Runnable&gt;(url.getPositiveParameter(CONNECT_QUEUE_CAPACITY, Integer.MAX_VALUE)),</span></span>\n<span class="line"><span>            new NamedThreadFactory(threadName, true),</span></span>\n<span class="line"><span>            new AbortPolicyWithReport(threadName, url)</span></span>\n<span class="line"><span>    );</span></span>\n<span class="line"><span>    queuewarninglimit = url.getParameter(CONNECT_QUEUE_WARNING_SIZE, DEFAULT_CONNECT_QUEUE_WARNING_SIZE);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 ConnectionOrderedChannelHandler 的 connected() 方法和 disconnected() 方法实现中，会将连接建立和断开事件交给上述 connectionExecutor 线程池排队处理。</p><p>在上面介绍 WrappedChannelHandler 各个实现的时候，我们会看到其中有针对 ThreadlessExecutor 这种线程池类型的特殊处理，例如，ExecutionChannelHandler.received() 方法中就有如下的分支逻辑：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void received(Channel channel, Object message) throws RemotingException {</span></span>\n<span class="line"><span>    // 获取线程池（请求绑定的线程池或是公共线程池）</span></span>\n<span class="line"><span>    ExecutorService executor = getPreferredExecutorService(message);</span></span>\n<span class="line"><span>    if (message instanceof Request) { // 请求消息直接提交给线程池处理</span></span>\n<span class="line"><span>        executor.execute(new ChannelEventRunnable(channel, handler, ChannelState.RECEIVED, message));</span></span>\n<span class="line"><span>    } else if (executor instanceof ThreadlessExecutor) {</span></span>\n<span class="line"><span>        // 针对ThreadlessExecutor这种线程池类型的特殊处理</span></span>\n<span class="line"><span>        executor.execute(new ChannelEventRunnable(channel, handler, ChannelState.RECEIVED, message));</span></span>\n<span class="line"><span>    } else {</span></span>\n<span class="line"><span>        handler.received(channel, message);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="threadlessexecutor-优化" tabindex="-1"><a class="header-anchor" href="#threadlessexecutor-优化"><span>ThreadlessExecutor 优化</span></a></h4><p>ThreadlessExecutor 是一种特殊类型的线程池，与其他正常的线程池最主要的区别是：<strong>ThreadlessExecutor 内部不管理任何线程</strong>。</p><p>我们可以调用 ThreadlessExecutor 的execute() 方法，将任务提交给这个线程池，但是这些提交的任务不会被调度到任何线程执行，而是存储在阻塞队列中，只有当其他线程调用 ThreadlessExecutor.waitAndDrain() 方法时才会真正执行。也说就是，执行任务的与调用 waitAndDrain() 方法的是同一个线程。</p><p>**那为什么会有 ThreadlessExecutor 这个实现呢？**这主要是因为在 Dubbo 2.7.5 版本之前，在 WrappedChannelHandler 中会为每个连接启动一个线程池。</p><blockquote><p>老版本中没有 ExecutorRepository 的概念，不会根据 URL 复用同一个线程池，而是通过 SPI 找到 ThreadPool 实现创建新线程池。</p></blockquote><p>此时，Dubbo Consumer 同步请求的线程模型如下图所示：</p><figure><img src="'+t+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Dubbo Consumer 同步请求线程模型</p><p>从图中我们可以看到下面的请求-响应流程：</p><ol><li>业务线程发出请求之后，拿到一个 Future 实例。</li><li>业务线程紧接着调用 Future.get() 阻塞等待请求结果返回。</li><li>当响应返回之后，交由连接关联的独立线程池进行反序列化等解析处理。</li><li>待处理完成之后，将业务结果通过 Future.set() 方法返回给业务线程。</li></ol><p>在这个设计里面，Consumer 端会维护一个线程池，而且线程池是按照连接隔离的，即每个连接独享一个线程池。这样，当面临需要消费大量服务且并发数比较大的场景时，例如，典型网关类场景，可能会导致 Consumer 端线程个数不断增加，导致线程调度消耗过多 CPU ，也可能因为线程创建过多而导致 OOM。</p><p>为了解决上述问题，Dubbo 在 2.7.5 版本之后，<strong>引入了 ThreadlessExecutor</strong>，将线程模型修改成了下图的样子：</p><figure><img src="'+d+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>引入 ThreadlessExecutor 后的结构图</p><ol><li>业务线程发出请求之后，拿到一个 Future 对象。</li><li>业务线程会调用 ThreadlessExecutor.waitAndDrain() 方法，waitAndDrain() 方法会在阻塞队列上等待。</li><li>当收到响应时，IO 线程会生成一个任务，填充到 ThreadlessExecutor 队列中，</li><li>业务线程会将上面添加的任务取出，并在本线程中执行。得到业务结果之后，调用 Future.set() 方法进行设置，此时 waitAndDrain() 方法返回。</li><li>业务线程从 Future 中拿到结果值。</li></ol><p>了解了 ThreadlessExecutor 出现的缘由之后，接下来我们再深入了解一下 ThreadlessExecutor 的核心实现。首先是 ThreadlessExecutor 的核心字段，有如下几个。</p><ul><li>queue（LinkedBlockingQueue类型）：阻塞队列，用来在 IO 线程和业务线程之间传递任务。</li><li>waiting、finished（Boolean类型）：ThreadlessExecutor 中的 waitAndDrain() 方法一般与一次 RPC 调用绑定，只会执行一次。当后续再次调用 waitAndDrain() 方法时，会检查 finished 字段，若为true，则此次调用直接返回。当后续再次调用 execute() 方法提交任务时，会根据 waiting 字段决定任务是放入 queue 队列等待业务线程执行，还是直接由 sharedExecutor 线程池执行。</li><li>sharedExecutor（ExecutorService类型）：ThreadlessExecutor 底层关联的共享线程池，当业务线程已经不再等待响应时，会由该共享线程执行提交的任务。</li><li>waitingFuture（CompletableFuture类型）：指向请求对应的 DefaultFuture 对象，其具体实现我们会在后面的课时详细展开介绍。</li></ul><p><strong>ThreadlessExecutor 的核心逻辑在 execute() 方法和 waitAndDrain() 方法</strong>**。**execute() 方法相对简单，它会根据 waiting 状态决定任务提交到哪里，相关示例代码如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void execute(Runnable runnable) {</span></span>\n<span class="line"><span>    synchronized (lock) {</span></span>\n<span class="line"><span>        if (!waiting) { // 判断业务线程是否还在等待响应结果</span></span>\n<span class="line"><span>            // 不等待，则直接交给共享线程池处理任务</span></span>\n<span class="line"><span>            sharedExecutor.execute(runnable); </span></span>\n<span class="line"><span>        } else {// 业务线程还在等待，则将任务写入队列，然后由业务线程自己执行</span></span>\n<span class="line"><span>            queue.add(runnable);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>waitAndDrain() 方法中首先会检测 finished 字段值，然后获取阻塞队列中的全部任务并执行，执行完成之后会修改finished和 waiting 字段，标识当前 ThreadlessExecutor 已使用完毕，无业务线程等待。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void waitAndDrain() throws InterruptedException {</span></span>\n<span class="line"><span>    if (finished) { // 检测当前ThreadlessExecutor状态</span></span>\n<span class="line"><span>        return;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 获取阻塞队列中获取任务</span></span>\n<span class="line"><span>    Runnable runnable = queue.take();</span></span>\n<span class="line"><span>    synchronized (lock) {</span></span>\n<span class="line"><span>        waiting = false; // 修改waiting状态</span></span>\n<span class="line"><span>        runnable.run(); // 执行任务</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    runnable = queue.poll(); // 如果阻塞队列中还有其他任务，也需要一并执行</span></span>\n<span class="line"><span>    while (runnable != null) {</span></span>\n<span class="line"><span>        runnable.run(); // 省略异常处理逻辑</span></span>\n<span class="line"><span>        runnable = queue.poll();</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    finished = true; // 修改finished状态</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>到此为止，Transporter 层对 ChannelHandler 的实现就介绍完了，其中涉及了多个 ChannelHandler 的装饰器，为了帮助你更好地理解，这里我们回到 NettyServer 中，看看它是如何对上层 ChannelHandler 进行封装的。</p><p>在 NettyServer 的构造方法中会调用 ChannelHandlers.wrap() 方法对传入的 ChannelHandler 对象进行修饰：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>protected ChannelHandler wrapInternal(ChannelHandler handler, URL url) {</span></span>\n<span class="line"><span>    return new MultiMessageHandler(new HeartbeatHandler(ExtensionLoader.getExtensionLoader(Dispatcher.class)</span></span>\n<span class="line"><span>            .getAdaptiveExtension().dispatch(handler, url)));</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>结合前面的分析，我们可以得到下面这张图：</p><figure><img src="'+c+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Server 端 ChannelHandler 结构图</p><p>我们可以在创建 NettyServerHandler 的地方添加断点 Debug 得到下图，也印证了上图的内容：</p><figure><img src="'+u+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h3><p>本课时我们重点介绍了 Dubbo Transporter 层中 Client、 Channel、ChannelHandler 相关的实现以及优化。</p><p>首先我们介绍了 AbstractClient 抽象接口以及基于 Netty 4 的 NettyClient 实现。接下来，介绍了 AbstractChannel 抽象类以及 NettyChannel 实现。最后，我们深入分析了 ChannelHandler 接口实现，其中详细分析 WrappedChannelHandler 等关键 ChannelHandler 实现，以及 ThreadlessExecutor 优化。</p>',93)]))}]]),v=JSON.parse('{"path":"/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98/20%20%20Transporter%20%E5%B1%82%E6%A0%B8%E5%BF%83%E5%AE%9E%E7%8E%B0%EF%BC%9A%E7%BC%96%E8%A7%A3%E7%A0%81%E4%B8%8E%E7%BA%BF%E7%A8%8B%E6%A8%A1%E5%9E%8B%E4%B8%80%E6%96%87%E6%89%93%E5%B0%BD%EF%BC%88%E4%B8%8B%EF%BC%89.html","title":"20  Transporter 层核心实现：编解码与线程模型一文打尽（下）","lang":"zh-CN","frontmatter":{"description":"20 Transporter 层核心实现：编解码与线程模型一文打尽（下） 在上一课时中，我们深入分析了 Transporter 层中 Server 相关的核心抽象类以及基于 Netty 4 的实现类。本课时我们继续分析 Transporter 层中剩余的核心接口实现，主要涉及 Client 接口、Channel 接口、ChannelHandler 接口...","head":[["meta",{"property":"og:url","content":"https://chenmingxing1012.github.io/blog/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98/20%20%20Transporter%20%E5%B1%82%E6%A0%B8%E5%BF%83%E5%AE%9E%E7%8E%B0%EF%BC%9A%E7%BC%96%E8%A7%A3%E7%A0%81%E4%B8%8E%E7%BA%BF%E7%A8%8B%E6%A8%A1%E5%9E%8B%E4%B8%80%E6%96%87%E6%89%93%E5%B0%BD%EF%BC%88%E4%B8%8B%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"凡人修码传"}],["meta",{"property":"og:title","content":"20  Transporter 层核心实现：编解码与线程模型一文打尽（下）"}],["meta",{"property":"og:description","content":"20 Transporter 层核心实现：编解码与线程模型一文打尽（下） 在上一课时中，我们深入分析了 Transporter 层中 Server 相关的核心抽象类以及基于 Netty 4 的实现类。本课时我们继续分析 Transporter 层中剩余的核心接口实现，主要涉及 Client 接口、Channel 接口、ChannelHandler 接口..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-07T05:33:45.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-07T05:33:45.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"20  Transporter 层核心实现：编解码与线程模型一文打尽（下）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-06-07T05:33:45.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"韩跑跑\\",\\"url\\":\\"https://chenmingxing1012.github.io/blog/\\"}]}"]]},"headers":[{"level":3,"title":"Client 继承路线分析","slug":"client-继承路线分析","link":"#client-继承路线分析","children":[]},{"level":3,"title":"Channel 继承线分析","slug":"channel-继承线分析","link":"#channel-继承线分析","children":[]},{"level":3,"title":"ChannelHandler 继承线分析","slug":"channelhandler-继承线分析","link":"#channelhandler-继承线分析","children":[]},{"level":3,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"createdTime":1780673609000,"updatedTime":1780810425000,"contributors":[{"name":"chenmingxing","email":"1060303243@qq.com","commits":1}]},"readingTime":{"minutes":15.47,"words":4642},"filePathRelative":"column/Dubbo源码解读与实战/20  Transporter 层核心实现：编解码与线程模型一文打尽（下）.md","localizedDate":"2026年6月5日","excerpt":"\\n<p>在上一课时中，我们深入分析了 Transporter 层中 Server 相关的核心抽象类以及基于 Netty 4 的实现类。本课时我们继续分析 Transporter 层中剩余的核心接口实现，主要涉及 Client 接口、Channel 接口、ChannelHandler 接口，以及相关的关键组件。</p>\\n<h3>Client 继承路线分析</h3>\\n<p>在上一课时分析 AbstractEndpoint 的时候可以看到，除了 AbstractServer 这一条继承线之外，还有 AbstractClient 这条继承线，它是对客户端的抽象。AbstractClient 中的核心字段有如下几个。</p>","autoDesc":true}')}}]);